class V1LinterResult(BaseModel):
    """
    The meta parent_kind can take one of two values - PackageVersion or RepositoryVersion.
    """

    context: V1Context
    """
    Context for the repository version will be automatically updated
    to that of the version, unless it is a CI run.
    """
    meta: V1Meta
    """
    Meta identifies the object.
    """
    spec: V1LinterResultSpec
    tenant_meta: V1TenantMeta | None = None
    """
    Linter results are associated with a tenant and namespace.
    """
    uuid: str | None = None
    """
    The UUID of a linter result.
    """


class V1LinterResultSpec(BaseModel):
    ai_result: V1AIResult | None = None
    aisast: V1AISastSummary | None = None
    distribution_format: V1DistributionFormatType | None = (
        'DISTRIBUTION_FORMAT_TYPE_UNSPECIFIED'
    )
    """
    The distribution format of the package.
    """
    ecosystem: V1Ecosystem | None = 'ECOSYSTEM_UNSPECIFIED'
    """
    The result ecosystem.
    """
    endor_fingerprint: SpecEndorFingerprint | None = None
    extra_key: str
    """
    Additional information that may result in creating a unique linter result.
    In some cases we may receive multiple results for the same project and the same file and we
    want to have multiple entries for the same field like parent_uuid, meta.name, and physical_location.
    By setting different values in this field, we will be able to create a separate result.
    Essentially, we will have a unique entry per field.
    """
    fingerprint_count: int | None = None
    fingerprints: list[str] | None = None
    """
    The list and count of found fingerprints. The counter is maintained
    to ease the retrieval of these records in the analytics phase.
    """
    level: SpecLinterResultLevel
    """
    The level of the result.
    """
    linter_correctness_analyses: list[LinterCorrectnessAnalyse] | None = None
    """
    An analysis of the linter result.
    """
    origin: SpecLinterResultOrigin
    """
    The origin of the result.
    """
    project_uuid: str
    """
    The UUID of the project to which this result is related.
    """
    ref: str | None = None
    """
    The Git reference of the repository version.
    """
    sarif_result: V1SarifResult | None = None
    secret: V1SecretSummary | None = None
    semgrep: V1SemgrepSummary | None = None
    storage_location: str | None = None
    """
    The storage location of the package related to this linter result.
    """
    suppressed: bool | None = None
    """
    Result was suppressed by semgrep (e.g. because of a "nosemgrep" code annotation).
    """
    version: str | None = None


